(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>\"]/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"insulation-r-value-series",fields:[{"key":"rValues","label":"각 층 R값","type":"textarea","placeholder":"예: 0.5, 2.1, 0.8","default":"","options":[],"raw":true}],hint:"단위체계를 동일하게 맞춘 R값만 합산하세요.",compute:function(x){var a=String(x.rValues||"").split(/[\s,;]+/).filter(Boolean).map(Number);if(!a.length||a.some(function(v){return !Number.isFinite(v)||v<=0;}))return{error:"0보다 큰 R값을 쉼표나 공백으로 입력해 주세요."};var total=a.reduce(function(s,v){return s+v;},0);return{totalR:total,uValue:1/total,layers:a.length};},format:function(r,api){return api.resultCard("총 열저항 R",api.formatNumber(r.totalR,4),"단열층 "+r.layers+"개")+api.resultCard("열관류율 U",api.formatNumber(r.uValue,6),"1 / R");}},{id:"net-wall-area",fields:[{"key":"wallLengthM","label":"벽 전체 길이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"wallHeightM","label":"벽 높이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"openingsAreaM2","label":"창문·문 면적 합계 (㎡)","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"wastePercent","label":"여유율 (%)","type":"number","placeholder":"","default":"10","options":[],"raw":false}],hint:"",compute:function(x){var l=Number(x.wallLengthM),h=Number(x.wallHeightM),o=Number(x.openingsAreaM2),w=Number(x.wastePercent);if(![l,h,o,w].every(Number.isFinite)||l<=0||h<=0||o<0||w<0)return{error:"벽 길이와 높이는 0보다 크게, 제외면적과 여유율은 0 이상으로 입력해 주세요."};var gross=l*h;if(o>gross)return{error:"창문·문 면적이 전체 벽면보다 큽니다."};var net=gross-o;return{grossArea:gross,netArea:net,requiredArea:net*(1+w/100)};},format:function(r,api){return api.resultCard("순 벽면 면적",api.formatNumber(r.netArea,2)+"㎡","전체 "+api.formatNumber(r.grossArea,2)+"㎡")+api.resultCard("여유 포함 준비면적",api.formatNumber(r.requiredArea,2)+"㎡","");}},{id:"grout-volume-estimate",fields:[{"key":"tileLengthMm","label":"타일 길이 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"tileWidthMm","label":"타일 너비 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"jointWidthMm","label":"줄눈 폭 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"jointDepthMm","label":"줄눈 깊이 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"areaM2","label":"시공 면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"타일 배치와 실제 충진률에 따라 차이가 날 수 있습니다.",compute:function(x){var l=Number(x.tileLengthMm),w=Number(x.tileWidthMm),j=Number(x.jointWidthMm),d=Number(x.jointDepthMm),a=Number(x.areaM2);if(![l,w,j,d,a].every(Number.isFinite)||l<=0||w<=0||j<=0||d<=0||a<=0)return{error:"모든 치수와 면적은 0보다 크게 입력해 주세요."};var liters=a*((l+w)/(l*w))*j*d;return{volumeLiters:liters,volumeMl:liters*1000,withWasteLiters:liters*1.1};},format:function(r,api){return api.resultCard("이론 줄눈재 부피",api.formatNumber(r.volumeLiters,3)+"L",api.formatNumber(r.volumeMl,0)+"mL")+api.resultCard("10% 여유 포함",api.formatNumber(r.withWasteLiters,3)+"L","");}},{id:"floor-leveling-compound",fields:[{"key":"areaM2","label":"바닥 면적 (㎡)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"thicknessMm","label":"평균 두께 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"coveragePerBag","label":"포대 1개 시공량 (㎡·mm)","type":"number","placeholder":"","default":"12","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.areaM2),t=Number(x.thicknessMm),c=Number(x.coveragePerBag);if(![a,t,c].every(Number.isFinite)||a<=0||t<=0||c<=0)return{error:"면적·두께·포대당 시공량은 0보다 크게 입력해 주세요."};var units=a*t/c;return{exactBags:units,bags:Math.ceil(units),volumeLiters:a*t};},format:function(r,api){return api.resultCard("필요 포대",api.formatNumber(r.bags,0)+"포","계산값 "+api.formatNumber(r.exactBags,2)+"포")+api.resultCard("시공 체적",api.formatNumber(r.volumeLiters,1)+"L","");}},{id:"deck-board-count",fields:[{"key":"deckWidthM","label":"데크 폭 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"deckLengthM","label":"데크 길이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"boardWidthMm","label":"판재 폭 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"gapMm","label":"판재 간격 (mm)","type":"number","placeholder":"","default":"5","options":[],"raw":false},{"key":"wastePercent","label":"여유율 (%)","type":"number","placeholder":"","default":"10","options":[],"raw":false}],hint:"",compute:function(x){var w=Number(x.deckWidthM),l=Number(x.deckLengthM),b=Number(x.boardWidthMm),g=Number(x.gapMm),p=Number(x.wastePercent);if(![w,l,b,g,p].every(Number.isFinite)||w<=0||l<=0||b<=0||g<0||p<0)return{error:"데크 치수와 판재 폭은 0보다 크게, 간격과 여유율은 0 이상으로 입력해 주세요."};var base=Math.ceil(w*1000/(b+g));var boards=Math.ceil(base*(1+p/100));return{baseBoards:base,boards:boards,totalLengthM:boards*l,deckArea:w*l};},format:function(r,api){return api.resultCard("필요 판재 수",api.formatNumber(r.boards,0)+"장","기본 "+r.baseBoards+"장")+api.resultCard("판재 총길이",api.formatNumber(r.totalLengthM,2)+"m","데크 "+api.formatNumber(r.deckArea,2)+"㎡");}},{id:"rainwater-use-days",fields:[{"key":"storedLiters","label":"저장량 (L)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"dailyUseLiters","label":"하루 사용량 (L)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"lossPercent","label":"손실률 (%)","type":"number","placeholder":"","default":"5","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.storedLiters),d=Number(x.dailyUseLiters),l=Number(x.lossPercent);if(![s,d,l].every(Number.isFinite)||s<0||d<=0||l<0||l>100)return{error:"저장량은 0 이상, 하루 사용량은 0보다 크게, 손실률은 0~100%로 입력해 주세요."};var usable=s*(1-l/100);return{usableLiters:usable,days:usable/d,fullDays:Math.floor(usable/d)};},format:function(r,api){return api.resultCard("사용가능일수",api.formatNumber(r.days,2)+"일","완전 사용 "+r.fullDays+"일")+api.resultCard("실사용 가능량",api.formatNumber(r.usableLiters,1)+"L","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
